                [0,4,8], [2,4,6]           // 对角线
            ];

            // 更新状态显示
            function updateStatus(message, type) {
                statusDiv.textContent = message;
                // 移除所有状态类
                statusDiv.classList.remove('win', 'lose', 'draw');
                if (type) {
                    statusDiv.classList.add(type);
                }
            }

            // 检查胜负或平局
            function checkGame() {
                // 检查获胜
                for (let pattern of winPatterns) {
                    const [a, b, c] = pattern;
                    if (boardState[a] && boardState[a] === boardState[b] && boardState[a] === boardState[c]) {
                        // 有人赢了
                        const winner = boardState[a];
                        gameOver = true;
                        // 标记获胜格子（可选，用于样式）
                        pattern.forEach(idx => {
                            cells[idx].classList.add('game-over');
                        });
                        // 所有格子都不可点击
                        cells.forEach(cell => cell.classList.add('game-over'));
                        // 更新状态
                        updateStatus(`🏆 ${winner} 获胜！`, 'win');
                        return true; // 游戏结束
                    }
                }

                // 检查平局：是否所有格子都被填满且没有胜者
                if (boardState.every(cell => cell !== null)) {
                    gameOver = true;
                    cells.forEach(cell => cell.classList.add('game-over'));
                    updateStatus('🤝 平局！', 'draw');
                    return true;
                }

                return false; // 游戏继续
            }

            // 处理格子点击
            function handleCellClick(event) {
                const cell = event.currentTarget;
                const index = parseInt(cell.dataset.index, 10);

                // 如果游戏结束或格子已被占用，忽略点击
                if (gameOver || boardState[index] !== null) return;

                // 更新棋盘状态
                boardState[index] = currentPlayer;
                cell.textContent = currentPlayer;
                cell.classList.add('taken');
                // 添加对应玩家颜色类
                if (currentPlayer === 'X') {
                    cell.classList.add('x-move');
                } else {
                    cell.classList.add('o-move');
                }

                // 检查游戏是否结束
                const ended = checkGame();
                if (ended) {
                    // 游戏结束，不需要切换玩家
                    return;
                }

                // 切换玩家
                currentPlayer = (currentPlayer === 'X') ? 'O' : 'X';
                updateStatus(`轮到 ${currentPlayer}`);
            }

            // 重置游戏
            function resetGame() {
                // 重置状态
                boardState.fill(null);
                currentPlayer = 'X';
                gameOver = false;

                // 清除棋盘显示
                cells.forEach(cell => {
                    cell.textContent = '';
                    cell.classList.remove('taken', 'x-move', 'o-move', 'game-over');
                });

                // 更新状态
                updateStatus('轮到 X');
            }

            // 绑定事件
            cells.forEach(cell => {
                cell.addEventListener('click', handleCellClick);
                // 添加 tabindex 以支持键盘导航 (按 Tab 聚焦，按 Enter/Space 触发点击)
                cell.setAttribute('tabindex', '0');
                // 为了让键盘操作更友好，可以增加 keydown 事件
                cell.addEventListener('keydown', (e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                        e.preventDefault();
                        cell.click();
                    }
                });
            });

            resetBtn.addEventListener('click', resetGame);

            // 初始状态
            updateStatus('轮到 X');
        })();
    </script>
</body>
</html>
