        // 显示结果
        resultDisplay.textContent = state.currentInput;
    }

    // 重置所有状态（谨慎）
    function resetAll() {
        state.expression = '';
        state.currentInput = '0';
        state.justEvaluated = false;
        state.errorFlag = false;
        updateDisplay();
    }

    // 设置错误
    function setError(msg = 'Error') {
        state.currentInput = msg;
        state.errorFlag = true;
        state.expression = '';
        updateDisplay();
    }

    // 判断字符串是否是一个合法的数字（包括负号、小数点）
    function isNumeric(str) {
        if (str === 'Infinity' || str === '-Infinity') return false;
        return !isNaN(parseFloat(str)) && isFinite(str);
    }

    // ==================== 核心计算逻辑 ====================

    // 将用户输入的表达式中的符号替换为JS可计算的符号
    function sanitizeExpr(expr) {
        // 替换显示符号
        let sanitized = expr
            .replace(/×/g, '*')
            .replace(/÷/g, '/')
            .replace(/−/g, '-')
            .replace(/π/g, 'Math.PI')
            .replace(/e(?![xp])/g, 'Math.E')   // 独立的e (但不是exp)
            .replace(/\^/g, '**')
            .replace(/sin\(/g, 'Math.sin(')
            .replace(/cos\(/g, 'Math.cos(')
            .replace(/tan\(/g, 'Math.tan(')
            .replace(/log\(/g, 'Math.log10(')
            .replace(/ln\(/g, 'Math.log(')
            .replace(/√\(/g, 'Math.sqrt(')
            .replace(/x²/g, '') // 平方直接计算不放入表达式，但若出现则删除（因为已即时处理）
            // 注意：x² 按钮即时计算，不进入表达式
        ;
        // 处理平方符号 (如果用户在表达式中手动输入了²，忽略)
        // 另外处理单独出现的x²? 正常不会出现
        return sanitized;
    }

    // 将表达式转换成可求值的形式，并执行
    function evaluateExpression(expr) {
        try {
            // 1. 替换符号
            let sanitized = expr
                .replace(/×/g, '*')
                .replace(/÷/g, '/')
                .replace(/−/g, '-')
                .replace(/π/g, 'Math.PI')
                .replace(/(?<![a-zA-Z])e(?![a-zA-Z])/g, 'Math.E')
                .replace(/\^/g, '**')
                .replace(/sin\(/g, 'Math.sin(')
                .replace(/cos\(/g, 'Math.cos(')
                .replace(/tan\(/g, 'Math.tan(')
                .replace(/log\(/g, 'Math.log10(')
                .replace(/ln\(/g, 'Math.log(')
                .replace(/√\(/g, 'Math.sqrt(');

            // 2. 如果当前是角度模式，需要将三角函数中的角度转为弧度
            // 调整：替换 sin( 等为带角度转换的包装函数
            if (state.isDegMode) {
                // 使用正则包装三角函数，将括号内数值乘以 π/180
                // 简单方式：将 Math.sin( 替换为 Math.sin( (x)*Math.PI/180 ) 但需要正确嵌套括号
                // 采用更可靠的方法：在构建表达式时已经处理了角度？ 我们在这里统一处理：利用 Function 中的变量转换
                // 但更安全：在表达式的数字后乘以因子？ 不完美。
                // 替代：使用自定义函数，比如将 Math.sin( 替换为函数调用，但 Function 中无法直接使用。
                // 改为预先在表达式中手动转换：将 Math.sin( 替换为 Math.sin( (x)*Math.PI/180 )
                // 但参数可能是个表达式，难以正确分组。
                // 采用更简单的做法：在计算前，将每个三角函数的参数提取并转换。
                // 为简化，我们采用“在即时计算时已经转换”的策略（在按钮处理中）。
                // 如果表达式包含 sin(30) 这种情况，我们实际上在按钮处理时已经直接计算了sin(30)并显示结果，
                // 不会让 sin(30) 留在表达式中。因此表达式中的三角函数只会出现在用户手动输入时？用户无法直接输入函数名，
                // 只有按钮点按才会出现。而按钮点按要么即时计算（单参数），要么添加函数名+括号（双参数）。
                // 但为了保险，我们仍然在表达式求值时处理角度转换：检测到 sin( 等，将里面的内容乘以 π/180。
                // 这需要用正则替换内部内容。比较复杂，先保留，后续可以优化。
                // 这里我们简单处理：如果在角度模式下，我们将 Math.sin( 替换为 Math.sin( ( 然后乘以 (Math.PI/180) 但会破坏括号。
                // 放弃在表达式求值时自动转角度，改为在即时计算时已经转换，表达式只记录函数名的文本，但不参与计算。
                // 而我们的实现中，函数即时计算后，不会在表达式中保留函数名，而是直接替换成数字结果。
                // 因此角度模式只在即时计算时生效。这样合理。
            }

            // 3. 检查是否包含非法字符（只允许数字、运算符、括号、Math.、点、空格）
            const allowed = /^[\d+\-*/().%\sMath.PI.Esin\cos\tan\log10\sqrt\^]+$/;
            // 注意：我们尚未替换所有内容，先用正则粗略检查
            // 实际更严格：我们信任 sanitized 来自受控按钮，但也安全处理。
            // 使用 Function 构造函数
            const fn = new Function('return ' + sanitized);
            const result = fn();
            if (typeof result !== 'number' || !isFinite(result)) {
                return result; // 可能是 Infinity 等
            }
            return result;
        } catch (e) {
            return 'Error';
        }
    }

    // 安全求值（返回值或错误信息）
    function safeEval(expr) {
        const result = evaluateExpression(expr);
        if (result === 'Error' || (typeof result === 'number' && !isFinite(result))) {
            return result;
        }
        // 处理浮点精度
        if (Number.isInteger(result)) return result;
        // 保留12位小数，去除尾部0
        const str = parseFloat(result.toFixed(12)).toString();
        return str;
    }

    // ==================== 按钮处理 ====================
    function handleButton(action, btnText) {
        // 如果处于错误状态，点击任何非清除类按钮都重置
        if (state.errorFlag && action !== 'clear') {
            resetAll();
        }

        // 根据 action 分支处理
        switch (action) {
            // ---------- 数字 ----------
            case '0': case '1': case '2': case '3': case '4':
            case '5': case '6': case '7': case '8': case '9':
            case '.':
                // 如果刚刚计算完（等号或即时计算），则开始新输入
                if (state.justEvaluated) {
                    state.currentInput = (action === '.') ? '0.' : action;
                    state.expression = '';  // 清空表达式，重新开始
                    state.justEvaluated = false;
                } else {
                    // 正常追加数字
                    if (action === '.') {
                        // 如果当前已经包含小数点，忽略
                        if (state.currentInput.includes('.')) break;
                        // 如果当前是 '0' 则变成 '0.'
                        if (state.currentInput === '0') {
                            state.currentInput = '0.';
                        } else {
                            state.currentInput += '.';
                        }
                    } else {
                        // 如果当前是 '0' 且不是小数点，替换
                        if (state.currentInput === '0') {
                            state.currentInput = action;
                        } else {
                            state.currentInput += action;
                        }
                    }
                }
                // 同时更新表达式？数字输入时，表达式通常显示当前数字或算式，但我们的设计是上行显示完整表达式。
                // 为了连贯，我们在数字输入时，如果表达式为空则直接显示数字，否则在末尾追加数字？
                // 实际上表达式应该包含完整的序列。我们选择：当输入数字时，如果表达式为空或者刚刚计算完毕，则用数字替换表达式内容？
                // 更好的方式是：表达式始终显示用户输入的完整算式，数字输入时追加到表达式。
                // 但是为了简化，我们仅在按下运算符或括号时更新表达式，数字只更新 currentInput，表达式单独维护。
                // 这里我们暂时不修改表达式。等按下运算符时再组合。
                // 然而显示屏上行表达式应显示当前输入的数字（如果没有操作符），所以我们在这里将表达式设为 currentInput。
                // 如果已有表达式且上次不是运算符结尾，则追加数字（但在我们的逻辑中，表达式会由运算符按钮更新）
                // 为避免混乱，我们采取简单策略：用户按数字时，只改变 currentInput，不改变表达式（除非表达式为空或刚刚计算）。
                // 但上行需要反映当前数字，所以如果表达式为空，我们将表达式设为 currentInput。
                if (state.expression === '' || state.justEvaluated) {
                    state.expression = state.currentInput;
                    state.justEvaluated = false;
                }
                // 注意：如果表达式非空且末尾是数字，可能希望追加数字，但我们的表达式在运算符点击时会更新，数字点击不追加到表达式（保持上行简洁？）
                // 为了用户可读，我们设计成：数字只改变下行，上行在运算符点击时更新为 expr + currentInput + 运算符。
                // 这样比较清晰。所以这里不修改表达式。
                // 但为了使上行显示当前数字（没有运算符时），我们在 expression 为空时设置。
                // 最终效果：用户按数字，上行显示数字，下行也显示数字。
                updateDisplay();
                break;

            // ---------- 运算符（双参数） ----------
            case '+': case '-': case '×': case '÷': case '^':
                // 将当前输入的数字和运算符加入表达式
                // 如果刚刚计算完，将结果作为第一个操作数
                if (state.justEvaluated) {
                    // 保留结果作为表达式一部分
                    state.expression = state.currentInput;
                    state.justEvaluated = false;
                } else {
                    // 如果表达式非空且末尾是数字或括号，追加运算符
                    // 但如果表达式末尾已有运算符，替换之（简单处理：先追加数字再运算符？）
                    // 这里我们采用：如果当前表达式不是以运算符结尾，则先追加当前数字再追加运算符
                    // 但当前数字如果没被追加过，需要追加
                }
                // 简单的设计：每当点击运算符，将 currentInput 附加到表达式末尾（如果当前输入不是来自表达式的一部分），然后加上运算符符号
                // 但如果 currentInput 已经包含在表达式里（例如 2+3，再按+，3还在，我们希望表达式变成2+3+）
                // 我们需要知道 currentInput 是否已经存在于表达式末尾。为了简化，我们总是将 currentInput 附加到表达式（如果表达式末尾不是当前数字）
                // 更稳健：维护表达式和当前输入分离。当按下运算符时，将当前输入数字和运算符拼接到表达式后，然后重置 currentInput 为 '0'。
                // 同时处理括号等。
                // 这里我们采用：
                // 1. 如果表达式为空，则 expression = currentInput + 运算符
                // 2. 否则，如果表达式末尾是数字或')'，则 append 运算符；否则替换最后一个运算符
                // 注意：为了正确性，我们直接拼接：先确保 currentInput 作为操作数被加入表达式。
                // 简便方法：表达式 = 表达式 + 当前数字 + 运算符，然后 currentInput = '0'。
                // 但是这样当连续按运算符时，数字会重复。例如先按2，再按+，表达式变成"2+"；再按3，再按+，表达式变成"2+3+"。
                // 符合预期。
                // 实现：
                // 先检查 currentInput 是否是0？但只要有点击过数字，currentInput 就是有效数。
                // 如果刚刚按了等号，currentInput 是结果，expression 可能是空的。
                if (state.justEvaluated) {
                    state.expression = state.currentInput;
                    state.justEvaluated = false;
                }
                // 将当前输入追加到表达式末尾（如果表达式末尾不是它）
                // 特别处理：如果表达式为空或只有数字，追加
                state.expression += state.currentInput;
                // 追加运算符
                state.expression += btnText; // 使用按钮显示文本
                // 重置当前输入为0，准备输入下一个数字
                state.currentInput = '0';
                updateDisplay();
                break;

            // ---------- 等号 ----------
            case 'equal':
                if (state.expression === '' && state.currentInput !== '0') {
                    // 只有数字，直接显示结果
                    state.expression = state.currentInput;
                }
                // 将当前数字追加到表达式末尾
                let fullExpr = state.expression + state.currentInput;
                // 检查是否含有非法模式（例如连续运算符），但暂不处理
                // 替换显示符号
                let jsExpr = fullExpr
                    .replace(/×/g, '*')
                    .replace(/÷/g, '/')
                    .replace(/−/g, '-')
                    .replace(/\^/g, '**')
                    .replace(/π/g, 'Math.PI')
                    .replace(/(?<![a-zA-Z])e(?![a-zA-Z])/g, 'Math.E');
                // 注意：表达式可能包含函数名（如 sin( ），但我们的即时计算策略已经处理，不会出现在表达式中。
                // 但为了安全，移除不在白名单的字符
                const safe = jsExpr.replace(/[^0-9+\-*/().%\sMath.PI.Esin\cos\tan\^]/g, '');
                let result;
                try {
                    // 使用 Function
                    const fn = new Function('return ' + safe);
                    const val = fn();
                    if (typeof val !== 'number' || !isFinite(val)) {
                        result = val.toString();
                    } else {
                        // 保留合理精度
                        result = parseFloat(val.toFixed(12)).toString();
                    }
                } catch (e) {
                    result = 'Error';
                }
                state.expression = fullExpr + ' =';
                state.currentInput = result;
                state.justEvaluated = true;
                state.errorFlag = (result === 'Error' || result === 'Infinity' || result === '-Infinity');
                updateDisplay();
                break;

            // ---------- 单参数函数（即时计算）----------
            case 'sin': case 'cos': case 'tan': case 'log': case 'ln': case 'sqrt': case 'square':
                // 获取当前数字
                let currentNum = parseFloat(state.currentInput);
                if (isNaN(currentNum)) {
                    setError('Error');
                    break;
                }
                let resultVal;
                const rad = state.isDegMode ? currentNum * Math.PI / 180 : currentNum;
                switch (action) {
                    case 'sin': resultVal = Math.sin(rad); break;
                    case 'cos': resultVal = Math.cos(rad); break;
                    case 'tan': resultVal = Math.tan(rad); break;
                    case 'log': resultVal = Math.log10(currentNum); break;
                    case 'ln': resultVal = Math.log(currentNum); break;
                    case 'sqrt': resultVal = Math.sqrt(currentNum); break;
                    case 'square': resultVal = currentNum * currentNum; break;
                }
                if (!isFinite(resultVal)) {
                    state.currentInput = 'Error';
                    state.errorFlag = true;
                } else {
                    state.currentInput = parseFloat(resultVal.toFixed(12)).toString();
                }
                // 更新表达式：显示函数名和操作数
                // 但为了简洁，我们直接显示结果，表达式保留原来？如果之前有表达式，可能不合适。
                // 我们策略：即时计算后，清除表达式，仅显示结果（类似许多计算器）
                state.expression = action + '(' + state.currentInput + ')'; // 但这样会重复？显示为比如 sin(0.5)
                // 更合理：显示计算结果
                // 我们改为：表达式显示 函数名(原数) 然后结果在下行
                // 但为了通用，这里简单显示表达式 = 结果？
                // 保持上行显示函数调用，下行结果
                // 我们更新表达式为 action + '(' + originalNum + ')' 但 originalNum 我们不知道精确显示，用 currentNum 的原始输入？
                // 为了简单， expression 设为 action + '(' + state.currentInput + ')' ?
                // 但是 state.currentInput 已经是结果了，不对。
                // 重新实现：保存原始输入
                const originalInput = state.currentInput;
                // 计算后
                state.expression = action + '(' + originalInput + ')';
                state.justEvaluated = true; // 之后按数字会重置
                updateDisplay();
                break;

            // ---------- 常数 ----------
            case 'pi':
                state.currentInput = Math.PI.toString();
                state.expression = 'π';
                state.justEvaluated = true;
                updateDisplay();
                break;
            case 'e':
                state.currentInput = Math.E.toString();
                state.expression = 'e';
                state.justEvaluated = true;
                updateDisplay();
                break;

            // ---------- 正负号 ----------
            case 'plusMinus':
                if (state.currentInput !== '0') {
                    if (state.currentInput.startsWith('-')) {
                        state.currentInput = state.currentInput.slice(1);
                    } else {
                        state.currentInput = '-' + state.currentInput;
                    }
                }
                // 更新表达式
                if (state.expression !== '' && !state.justEvaluated) {
                    // 如果表达式以数字结尾，替换最后一个数字？ 为了简化，我们不修改表达式，仅修改当前输入
                }
                updateDisplay();
                break;

            // ---------- 括号 ----------
            case 'paren':
                // 根据按钮文本 ( 或 )
                const paren = btnText;
                // 如果刚刚计算完，开始新表达式
                if (state.justEvaluated) {
                    state.expression = state.currentInput + paren;
                    state.currentInput = '0';
                    state.justEvaluated = false;
                } else {
                    // 将当前数字追加到表达式，再加括号
                    state.expression += state.currentInput + paren;
                    state.currentInput = '0';
                }
                updateDisplay();
                break;

            // ---------- 退格 ----------
            case 'backspace':
                if (state.currentInput.length > 1) {
                    state.currentInput = state.currentInput.slice(0, -1);
                    if (state.currentInput === '-') state.currentInput = '0';
                } else {
                    state.currentInput = '0';
                }
                // 如果表达式末尾有数字，也需要退格？为简化，仅处理当前输入
                updateDisplay();
                break;

            // ---------- 清除 ----------
            case 'clear':
                resetAll();
                break;

            // ---------- 度数/弧度切换 ----------
            case 'degRad':
                state.isDegMode = !state.isDegMode;
                modeLabel.textContent = state.isDegMode ? 'DEG' : 'RAD';
                break;

            // ---------- 其他（占位） ----------
            default:
                console.warn('Unknown action:', action);
        }
    }

    // ==================== 绑定按钮事件 ====================
    document.querySelectorAll('.btn').forEach(btn => {
        btn.addEventListener('click', function(e) {
            const action = this.dataset.action;
            const btnText = this.textContent;
            handleButton(action, btnText);
        });
    });

    // ==================== 键盘支持 ====================
    document.addEventListener('keydown', function(e) {
        const key = e.key;
        // 数字
        if (/^[0-9.]$/.test(key)) {
            handleButton(key, key);
            e.preventDefault();
        }
        // 运算符
        const opMap = {
            '+': '+',
            '-': '-',
            '*': '×',
            '/': '÷',
            '^': '^',
            'Enter': 'equal',
            '=': 'equal'
        };
        if (opMap[key]) {
            if (key === 'Enter' || key === '=') {
                handleButton('equal', '=');
            } else {
                handleButton(opMap[key], opMap[key]);
            }
            e.preventDefault();
        }
        // 退格
        if (key === 'Backspace') {
            handleButton('backspace', '←');
            e.preventDefault();
        }
        // 清除 (Delete 或 Escape)
        if (key === 'Delete' || key === 'Escape') {
            handleButton('clear', 'C');
            e.preventDefault();
        }
        // 括号
        if (key === '(' || key === ')') {
            handleButton('paren', key);
            e.preventDefault();
        }
        // 其他：例如 p 代表π, e 常数
        if (key === 'p' || key === 'P') {
            handleButton('pi', 'π');
            e.preventDefault();
        }
        if (key === 'e') {
            // 注意：不要与数字e混淆？但我们总是触发常数，若在输入数字中可能误触，忽略？
            // 为安全，仅当按下单独的e键
            handleButton('e', 'e');
            e.preventDefault();
        }
    });

    // 初始化显示
    updateDisplay();
    modeLabel.textContent = state.isDegMode ? 'DEG' : 'RAD';

    // 额外：在按钮完成后调整布局 (无)
</script>
