template<typename Key, typename Value, typename Compare = std::less<Key>>
class ThreadSafeOrderedDict {
public:
    enum Color { RED, BLACK };

    struct Node {
        Key key;
        Value value;
        Color color;
        Node* left;
        Node* right;
        Node* parent;

        Node(const Key& k, const Value& v, Color c = RED)
            : key(k), value(v), color(c),
              left(nullptr), right(nullptr), parent(nullptr) {}
    };

    // 迭代器（只读，不持有锁，需外部确保线程安全）
    class const_iterator {
    public:
        using value_type = std::pair<Key, Value>;
        using reference = const value_type&;
        using pointer = const value_type*;
        using difference_type = std::ptrdiff_t;
        using iterator_category = std::forward_iterator_tag;

        const_iterator() : node_(nullptr), dict_(nullptr) {}
        const_iterator(Node* node, const ThreadSafeOrderedDict* dict) : node_(node), dict_(dict) {}

        value_type operator*() const {
            return { node_->key, node_->value };
        }

        const_iterator& operator++() {
            node_ = successor(node_);
            return *this;
        }

        const_iterator operator++(int) {
            const_iterator tmp = *this;
            ++(*this);
            return tmp;
        }

        bool operator==(const const_iterator& other) const {
            return node_ == other.node_;
        }

        bool operator!=(const const_iterator& other) const {
            return node_ != other.node_;
        }

    private:
        Node* node_;
        const ThreadSafeOrderedDict* dict_;

        Node* successor(Node* x) const {
            if (x == dict_->nil_) return dict_->nil_;
            if (x->right != dict_->nil_) {
                return dict_->minNode(x->right);
            }
            Node* y = x->parent;
            while (y != dict_->nil_ && x == y->right) {
                x = y;
                y = y->parent;
            }
            return y;
        }
    };

    // 构造函数
    ThreadSafeOrderedDict() : root_(nullptr) {
        nil_ = new Node(Key(), Value(), BLACK);
        nil_->left = nil_->right = nil_->parent = nil_;
        root_ = nil_;
        size_ = 0;
    }

    // 禁止拷贝
    ThreadSafeOrderedDict(const ThreadSafeOrderedDict&) = delete;
    ThreadSafeOrderedDict& operator=(const ThreadSafeOrderedDict&) = delete;

    ~ThreadSafeOrderedDict() {
        std::unique_lock lock(mutex_);
        clearTree(root_);
        delete nil_;
    }

    // ---------- 公共接口 ----------
    void insert(const Key& key, const Value& value) {
        std::unique_lock lock(mutex_);
        Node* z = new Node(key, value, RED);
        z->left = nil_;
        z->right = nil_;
        insertNode(z);
        insertFixup(z);
        ++size_;
    }

    bool find(const Key& key, Value& value) const {
        std::shared_lock lock(mutex_);
        Node* node = searchNode(root_, key);
        if (node != nil_) {
            value = node->value;
            return true;
        }
        return false;
    }

    bool erase(const Key& key) {
        std::unique_lock lock(mutex_);
        Node* z = searchNode(root_, key);
        if (z == nil_) {
            return false;
        }
        Node* y = z;
        Color y_original_color = y->color;
        Node* x;
        if (z->left == nil_) {
            x = z->right;
            transplant(z, z->right);
        } else if (z->right == nil_) {
            x = z->left;
            transplant(z, z->left);
        } else {
            y = minNode(z->right);
            y_original_color = y->color;
            x = y->right;
            if (y->parent == z) {
                x->parent = y;
            } else {
                transplant(y, y->right);
                y->right = z->right;
                y->right->parent = y;
            }
            transplant(z, y);
            y->left = z->left;
            y->left->parent = y;
            y->color = z->color;
        }
        if (y_original_color == BLACK) {
            deleteFixup(x);
        }
        delete z;
        --size_;
        return true;
    }

    size_t size() const {
        std::shared_lock lock(mutex_);
        return size_;
    }

    void clear() {
        std::unique_lock lock(mutex_);
        clearTree(root_);
        root_ = nil_;
        size_ = 0;
    }

    // 返回迭代器（必须在外界持有读锁时调用）
    const_iterator begin_locked() const {
        return const_iterator(minNode(root_), this);
    }

    const_iterator end_locked() const {
        return const_iterator(nil_, this);
    }

    // 带锁遍历
    template<typename Func>
    void for_each(Func func) const {
        std::shared_lock lock(mutex_);
        inorderTraverse(root_, func);
    }

private:
    // ---------- 红黑树核心函数 ----------
    void leftRotate(Node* x) {
        Node* y = x->right;
        x->right = y->left;
        if (y->left != nil_) {
            y->left->parent = x;
        }
        y->parent = x->parent;
        if (x->parent == nil_) {
            root_ = y;
        } else if (x == x->parent->left) {
            x->parent->left = y;
        } else {
            x->parent->right = y;
        }
        y->left = x;
        x->parent = y;
    }

    void rightRotate(Node* y) {
        Node* x = y->left;
        y->left = x->right;
        if (x->right != nil_) {
            x->right->parent = y;
        }
        x->parent = y->parent;
        if (y->parent == nil_) {
            root_ = x;
        } else if (y == y->parent->left) {
            y->parent->left = x;
        } else {
            y->parent->right = x;
        }
        x->right = y;
        y->parent = x;
    }

    void insertFixup(Node* z) {
        while (z->parent->color == RED) {
            if (z->parent == z->parent->parent->left) {
                Node* y = z->parent->parent->right;
                if (y->color == RED) {
                    z->parent->color = BLACK;
                    y->color = BLACK;
                    z->parent->parent->color = RED;
                    z = z->parent->parent;
                } else {
                    if (z == z->parent->right) {
                        z = z->parent;
                        leftRotate(z);
                    }
                    z->parent->color = BLACK;
                    z->parent->parent->color = RED;
                    rightRotate(z->parent->parent);
                }
            } else {
                Node* y = z->parent->parent->left;
                if (y->color == RED) {
                    z->parent->color = BLACK;
                    y->color = BLACK;
                    z->parent->parent->color = RED;
                    z = z->parent->parent;
                } else {
                    if (z == z->parent->left) {
                        z = z->parent;
                        rightRotate(z);
                    }
                    z->parent->color = BLACK;
                    z->parent->parent->color = RED;
                    leftRotate(z->parent->parent);
                }
            }
        }
        root_->color = BLACK;
    }

    void insertNode(Node* z) {
        Node* y = nil_;
        Node* x = root_;
        while (x != nil_) {
            y = x;
            if (comp_(z->key, x->key)) {
                x = x->left;
            } else {
                x = x->right;
            }
        }
        z->parent = y;
        if (y == nil_) {
            root_ = z;
        } else if (comp_(z->key, y->key)) {
            y->left = z;
        } else {
            y->right = z;
        }
    }

    void transplant(Node* u, Node* v) {
        if (u->parent == nil_) {
            root_ = v;
        } else if (u == u->parent->left) {
            u->parent->left = v;
        } else {
            u->parent->right = v;
        }
        v->parent = u->parent;
    }

    void deleteFixup(Node* x) {
        while (x != root_ && x->color == BLACK) {
            if (x == x->parent->left) {
                Node* w = x->parent->right;
                if (w->color == RED) {
                    w->color = BLACK;
                    x->parent->color = RED;
                    leftRotate(x->parent);
                    w = x->parent->right;
                }
                if (w->left->color == BLACK && w->right->color == BLACK) {
                    w->color = RED;
                    x = x->parent;
                } else {
                    if (w->right->color == BLACK) {
                        w->left->color = BLACK;
                        w->color = RED;
                        rightRotate(w);
                        w = x->parent->right;
                    }
                    w->color = x->parent->color;
                    x->parent->color = BLACK;
                    w->right->color = BLACK;
                    leftRotate(x->parent);
                    x = root_;
                }
            } else {
                Node* w = x->parent->left;
                if (w->color == RED) {
                    w->color = BLACK;
                    x->parent->color = RED;
                    rightRotate(x->parent);
                    w = x->parent->left;
                }
                if (w->right->color == BLACK && w->left->color == BLACK) {
                    w->color = RED;
                    x = x->parent;
                } else {
                    if (w->left->color == BLACK) {
                        w->right->color = BLACK;
                        w->color = RED;
                        leftRotate(w);
                        w = x->parent->left;
                    }
                    w->color = x->parent->color;
                    x->parent->color = BLACK;
                    w->left->color = BLACK;
                    rightRotate(x->parent);
                    x = root_;
                }
            }
        }
        x->color = BLACK;
    }

    Node* searchNode(Node* node, const Key& key) const {
        while (node != nil_) {
            if (comp_(key, node->key)) {
                node = node->left;
            } else if (comp_(node->key, key)) {
                node = node->right;
            } else {
                return node;
            }
        }
        return nil_;
    }

    Node* minNode(Node* node) const {
        while (node->left != nil_) {
            node = node->left;
        }
        return node;
    }

    Node* maxNode(Node* node) const {
        while (node->right != nil_) {
            node = node->right;
        }
        return node;
    }

    void inorderTraverse(Node* node, const std::function<void(const Key&, const Value&)>& func) const {
        if (node == nil_) return;
        inorderTraverse(node->left, func);
        func(node->key, node->value);
        inorderTraverse(node->right, func);
    }

    void clearTree(Node* node) {
        if (node == nil_) return;
        clearTree(node->left);
        clearTree(node->right);
        delete node;
    }

    // ---------- 成员变量 ----------
    Node* root_;
    Node* nil_;
    Compare comp_;
    mutable std::shared_mutex mutex_;
    size_t size_;
};

// ---------- 测试 ----------
void testSingleThread() {
    ThreadSafeOrderedDict<int, std::string> dict;

    dict.insert(3, "three");
    dict.insert(1, "one");
    dict.insert(4, "four");
    dict.insert(2, "two");

    std::cout << "Ordered traversal (single thread): ";
    dict.for_each([](int k, const std::string& v) {
        std::cout << "(" << k << ": " << v << ") ";
    });
    std::cout << std::endl;

    std::string val;
    assert(dict.find(2, val));
    assert(val == "two");
    assert(!dict.find(5, val));

    dict.erase(1);
    assert(dict.size() == 3);
    dict.for_each([](int k, const std::string& v) {
        std::cout << "(" << k << ": " << v << ") ";
    });
    std::cout << std::endl;
    dict.clear();
    assert(dict.size() == 0);
}

void testMultiThread() {
    ThreadSafeOrderedDict<int, int> dict;
    const int N = 1000;
    // 用多个线程并行插入
    std::vector<std::thread> threads;
    for (int i = 0; i < N; ++i) {
        threads.emplace_back([&dict, i]() {
            dict.insert(i, i * 10);
        });
    }
    for (auto& t : threads) t.join();

    std::cout << "Size after concurrent inserts: " << dict.size() << " (expected 1000)" << std::endl;
    assert(dict.size() == 1000);

    // 并行查找和删除
    threads.clear();
    std::atomic<int> found_count(0);
    for (int i = 0; i < N; ++i) {
        threads.emplace_back([&dict, i, &found_count]() {
            int val = -1;
            // 部分键存在，部分可能被其他线程删除
            if (dict.find(i, val)) {
                assert(val == i * 10);
                ++found_count;
            }
        });
    }
    for (auto& t : threads) t.join();
    std::cout << "Found " << found_count.load() << " keys during concurrent find." << std::endl;

    // 并清除除
    threads.clear();
    for (int i = 0; i < N; i += 2) { // 删除偶数键
        threads.emplace_back([&dict, i]() {
            dict.erase(i);
        });
    }
    for (auto& t : threads) t.join();

    // 验证有序性
    std::vector<int> keys;
    dict.for_each([&keys](int k, int v) {
        keys.push_back(k);
    });
    assert(std::is_sorted(keys.begin(), keys.end()));
    std::cout << "After concurrent erasures, sorted keys: ";
    for (int k : keys) std::cout << k << " ";
    std::cout << std::endl;
    std::cout << "Test passed!" << std::endl;
}

int main() {
    testSingleThread();
    testMultiThread();
    return 0;
}
