                if (full) {
                    // Remove row
                    for (let r = row; r > 0; r--) {
                        board[r] = board[r-1].slice();
                    }
                    board[0] = Array(COLS).fill(null);
                    linesCleared++;
                    // Check same row again (since rows shifted down)
                    continue;
                }
                row--;
            }

            if (linesCleared > 0) {
                // Simple scoring: 100 per line (no combo)
                score += linesCleared * 100;
                updateScore();
            }
        }

        // ---------- Drawing ----------
        function drawBlock(x, y, color) {
            ctx.fillStyle = color;
            ctx.fillRect(x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE - 1, BLOCK_SIZE - 1);
            // Optional border effect
            ctx.fillStyle = 'rgba(255,255,255,0.1)';
            ctx.fillRect(x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE - 1, 2);
            ctx.fillRect(x * BLOCK_SIZE, y * BLOCK_SIZE, 2, BLOCK_SIZE - 1);
        }

        function draw() {
            // Clear canvas
            ctx.fillStyle = '#0a0a0a';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // Draw board (locked pieces)
            for (let row = 0; row < ROWS; row++) {
                for (let col = 0; col < COLS; col++) {
                    const color = board[row][col];
                    if (color) {
                        drawBlock(col, row, color);
                    }
                }
            }

            // Draw current piece (if game not over)
            if (currentPiece && !gameOver) {
                const { shape, x, y, type } = currentPiece;
                const color = COLORS[type];
                for (let row = 0; row < shape.length; row++) {
                    for (let col = 0; col < shape[row].length; col++) {
                        if (shape[row][col] !== 0) {
                            const boardX = x + col;
                            const boardY = y + row;
                            if (boardY >= 0 && boardY < ROWS && boardX >= 0 && boardX < COLS) {
                                drawBlock(boardX, boardY, color);
                            }
                        }
                    }
                }
            }

            // Draw grid lines (subtle)
            ctx.strokeStyle = '#333';
            ctx.lineWidth = 0.5;
            for (let i = 0; i <= COLS; i++) {
                ctx.beginPath();
                ctx.moveTo(i * BLOCK_SIZE, 0);
                ctx.lineTo(i * BLOCK_SIZE, canvas.height);
                ctx.stroke();
            }
            for (let i = 0; i <= ROWS; i++) {
                ctx.beginPath();
                ctx.moveTo(0, i * BLOCK_SIZE);
                ctx.lineTo(canvas.width, i * BLOCK_SIZE);
                ctx.stroke();
            }
        }

        function updateScore() {
            scoreSpan.textContent = score;
        }

        // ---------- Game logic ----------
        function movePiece(dx, dy) {
            if (gameOver || !currentPiece) return false;
            const newX = currentPiece.x + dx;
            const newY = currentPiece.y + dy;
            if (!collides(currentPiece.shape, newX, newY)) {
                currentPiece.x = newX;
                currentPiece.y = newY;
                draw();
                return true;
            }
            // If dy >0 (down move) and collision, lock piece
            if (dy > 0) {
                lockPiece();
                draw();
                // After locking, gameOver may be set
            }
            return false;
        }

        function rotatePiece() {
            if (gameOver || !currentPiece) return;
            // Rotate clockwise: transpose and reverse each row
            const shape = currentPiece.shape;
            const rows = shape.length;
            const cols = shape[0].length; // assuming rectangular
            const rotated = Array.from({ length: cols }, (_, i) =>
                Array.from({ length: rows }, (_, j) => shape[rows - 1 - j][i])
            );
            // Check collision with new shape
            if (!collides(rotated, currentPiece.x, currentPiece.y)) {
                currentPiece.shape = rotated;
                draw();
            }
            // Simple: no wall kicks
        }

        function hardDrop() {
            if (gameOver || !currentPiece) return;
            while (!collides(currentPiece.shape, currentPiece.x, currentPiece.y + 1)) {
                currentPiece.y += 1;
            }
            lockPiece();
            draw();
        }

        // Game loop (called by requestAnimationFrame)
        function gameLoop(timestamp) {
            if (gameOver) {
                draw();
                // Stop loop
                return;
            }

            // Auto drop based on interval
            if (!lastDrop) lastDrop = timestamp;
            const elapsed = timestamp - lastDrop;
            if (elapsed >= dropInterval) {
                movePiece(0, 1);
                lastDrop = timestamp;
            }

            draw();
            animationId = requestAnimationFrame(gameLoop);
        }

        // ---------- Input handling ----------
        function handleKey(e) {
            if (gameOver) return;
            const key = e.key;
            // Prevent scrolling
            const controlKeys = ['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', ' '];
            if (controlKeys.includes(key)) {
                e.preventDefault();
            }

            switch (key) {
                case 'ArrowLeft':
                    movePiece(-1, 0);
                    break;
                case 'ArrowRight':
                    movePiece(1, 0);
                    break;
                case 'ArrowDown':
                    movePiece(0, 1);
                    break;
                case 'ArrowUp':
                    rotatePiece();
                    break;
                case ' ':
                    hardDrop();
                    break;
            }
        }

        // ---------- Start / Restart ----------
        function startGame() {
            // Reset state
            createBoard();
            gameOver = false;
            score = 0;
            updateScore();
            gameOverMsg.textContent = '';
            currentPiece = randomPiece();
            lastDrop = 0;

            // Cancel any existing animation
            if (animationId) {
                cancelAnimationFrame(animationId);
                animationId = null;
            }

            draw();
            animationId = requestAnimationFrame(gameLoop);
        }

        // ---------- Event listeners ----------
        window.addEventListener('keydown', handleKey);
        restartBtn.addEventListener('click', () => {
            startGame();
        });

        // Disable context menu on canvas (optional)
        canvas.addEventListener('contextmenu', (e) => e.preventDefault());

        // ---------- Initial start ----------
        startGame();
    })();
</script>
</body>
</html>
