<body>
<div class="container">
    <h1>🔌 SR 锁存器 (与非门实现)</h1>
    <div class="canvas-wrapper">
        <canvas id="latchCanvas" width="800" height="500"></canvas>
    </div>

    <div class="controls">
        <div class="control-group">
