    </div>
    <div class="footer">
        点击按钮切换输入 (1→0 或 0→1) · 红色表示逻辑 1 · 绿色表示逻辑 0
    </div>
</div>

<script>
    (function() {
        const canvas = document.getElementById('latchCanvas');
        const ctx = canvas.getContext('2d');

        // 输入状态
        let S = 1;   // 按钮显示: 1 代表高电平 (true)
        let R = 1;   // 按钮显示: 1 代表高电平

        // 锁存器内部状态
        let Q = 1;
        let Qbar = 0;

        // DOM 元素
        const btnS = document.getElementById('btnS');
        const btnR = document.getElementById('btnR');
        const qDisplay = document.getElementById('qDisplay');
        const qbarDisplay = document.getElementById('qbarDisplay');
        const stateBadge = document.getElementById('stateBadge');

        // 常量 - 布局坐标 (基于 800x500)
        const GATE_SIZE = 100;           // 门主体宽度
        const GATE_HEIGHT = 80;          // 门主体高度
        const G1_X = 250, G1_Y = 180;    // 门1 (左上) 位置 (三角形顶点)
        const G2_X = 450, G2_Y = 180;    // 门2 (右上) 位置

        // 绘制一个与非门 (NAND gate)
        // x, y 为三角尖顶点 (输出端) 的坐标
        // 门朝左 (输入在右边) 或者朝右？标准锁存器：门1的输入来自门2的输出，门2的输入来自门1的输出。
        // 为了布局清晰，让两个门相对放置：
        // 门1：输入在右边 (接受门2输出)，输出在左边 (送到门2输入)
        // 门2：输入在左边 (接受门1输出)，输出在右边 (送到门1输入)
        // 所以我们画两个方向不同的门。
        function drawNAND(x, y, direction) {
            // direction: 'left' 表示输出在左边 (门朝左), 'right' 表示输出在右边 (门朝右)
            const w = GATE_SIZE;
            const h = GATE_HEIGHT;
            const half = h / 2;
            // 计算门体矩形 (用于画主体)
            let rectX, rectY, rectW;
            if (direction === 'left') {
                // 输出在左边，三角形顶点在左边 (x,y) 是尖点? 实际上 NAND 符号：三角形左边输入，右边输出带小圆圈。
                // 但是为了交叉连线方便, 我们反转标准符号:
                // 画一个水平放置的 "先与后非" 形状：左边是输入线，右边是输出线，输出带小圆。
                // 但是锁存器连线上需要交叉，所以我们让门的输入从右侧来，输出到左侧去 (反向)。
                // 这样门水平翻转: 输入在右边，输出在左边 (带小圆)。
                // 三角形指向左边。
                // 主体: 左边一个三角形(尖端在左)，右边是一个圆弧? 标准与非门符号: 左边直线(两个输入)，右边圆弧+小圆圈。
                // 但为了简化，我们画一个左边凸起的半圆? 更简单: 画一个矩形表示主体? 不行, 需要识别性。
                // 采用简化的形状: 梯形? 我们绘制一个经典形状: 左边一个竖直线, 右边一个圆弧, 再加小圆圈。
                // 更简单: 直接画文字 "NAND"? 不太美观。用程序绘制标准符号:
                // 我们使用贝塞尔曲线绘制标准门形状:
                // 对于方向 'left': 门的输出在左边（小圆圈在左边），输入在右边（两条平行线）。
                // 标准 NAND 符号: 左侧是两个输入引线，中间一个“D”形（半圆+直线），右侧输出带小圆。
                // 为了简洁，我们绘制一个三角形（代表放大器）加上一个小圆圈在输出端，输入端用两条线表示。
                // 三角形指向输出方向。
                // 所以如果方向 'left'，三角形顶点在左边 (x,y)，底边在右边。
                // 这样更容易。
                const tipX = x;               // 顶点 (输出)
                const baseX = x + w;          // 底边 x
                const topY = y - half;
                const bottomY = y + half;
                // 绘制三角形
                ctx.beginPath();
                ctx.moveTo(tipX, y);
                ctx.lineTo(baseX, topY);
                ctx.lineTo(baseX, bottomY);
                ctx.closePath();
                ctx.fillStyle = '#e0e7ff';
                ctx.fill();
                ctx.strokeStyle = '#1e293b';
                ctx.lineWidth = 2;
                ctx.stroke();

                // 绘制小圆圈 (输出非)
                ctx.beginPath();
                ctx.arc(tipX - 10, y, 6, 0, 2 * Math.PI);
                ctx.fillStyle = '#e0e7ff';
                ctx.fill();
                ctx.stroke();

                // 绘制输入线 (从右边引出的两条线)
                const inputY1 = y - 20;
                const inputY2 = y + 20;
                ctx.beginPath();
                ctx.moveTo(baseX, inputY1);
                ctx.lineTo(baseX + 30, inputY1);
                ctx.stroke();
                ctx.beginPath();
                ctx.moveTo(baseX, inputY2);
                ctx.lineTo(baseX + 30, inputY2);
                ctx.stroke();

                // 返回输出点坐标 (小圆圈中心) 和输入点坐标 (输入线右端点)
                return {
                    output: { x: tipX - 10, y: y },
                    inputs: [
                        { x: baseX + 30, y: inputY1 },
                        { x: baseX + 30, y: inputY2 }
                    ]
                };
            } else { // 'right' 方向: 顶点在右边，底边在左边
                const tipX = x;               // 顶点 (输出)
                const baseX = x - w;          // 底边 x
                const topY = y - half;
                const bottomY = y + half;
                ctx.beginPath();
                ctx.moveTo(tipX, y);
                ctx.lineTo(baseX, topY);
                ctx.lineTo(baseX, bottomY);
                ctx.closePath();
                ctx.fillStyle = '#e0e7ff';
                ctx.fill();
                ctx.strokeStyle = '#1e293b';
                ctx.lineWidth = 2;
                ctx.stroke();

                // 小圆圈 (输出)
                ctx.beginPath();
                ctx.arc(tipX + 10, y, 6, 0, 2 * Math.PI);
                ctx.fillStyle = '#e0e7ff';
                ctx.fill();
                ctx.stroke();

                // 输入线 (从左边引出)
                const inputY1 = y - 20;
                const inputY2 = y + 20;
                ctx.beginPath();
                ctx.moveTo(baseX, inputY1);
                ctx.lineTo(baseX - 30, inputY1);
                ctx.stroke();
                ctx.beginPath();
                ctx.moveTo(baseX, inputY2);
                ctx.lineTo(baseX - 30, inputY2);
                ctx.stroke();

                return {
                    output: { x: tipX + 10, y: y },
                    inputs: [
                        { x: baseX - 30, y: inputY1 },
                        { x: baseX - 30, y: inputY2 }
                    ]
                };
            }
        }

        // 绘制灯泡 (逻辑电平指示)
        function drawBulb(x, y, radius, value, label) {
            // value: 1 or 0
            ctx.beginPath();
            ctx.arc(x, y, radius, 0, 2 * Math.PI);
            const color = value === 1 ? '#ef4444' : '#22c55e';
            ctx.fillStyle = color;
            ctx.fill();
            ctx.strokeStyle = '#1e293b';
            ctx.lineWidth = 2;
            ctx.stroke();

            // 添加阴影模拟发光
            ctx.beginPath();
            ctx.arc(x, y, radius + 3, 0, 2 * Math.PI);
            const glow = value === 1 ? 'rgba(239,68,68,0.3)' : 'rgba(34,197,94,0.3)';
            ctx.fillStyle = glow;
            ctx.fill();

            // 标签
            ctx.fillStyle = '#1e293b';
            ctx.font = 'bold 14px "Segoe UI", sans-serif';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'bottom';
            ctx.fillText(label, x, y - radius - 8);
        }

        // 绘制连接线（带拐角）
        function drawLine(points, color = '#1e293b', width = 2, dashed = false) {
            ctx.beginPath();
            ctx.moveTo(points[0].x, points[0].y);
            for (let i = 1; i < points.length; i++) {
                ctx.lineTo(points[i].x, points[i].y);
            }
            ctx.strokeStyle = color;
            ctx.lineWidth = width;
            if (dashed) ctx.setLineDash([6, 4]);
            else ctx.setLineDash([]);
            ctx.stroke();
            ctx.setLineDash([]);
        }

        // 绘制输入点 (S 和 R 的输入标签和引脚)
        function drawInputPin(x, y, value, label) {
            // 小圆点
            ctx.beginPath();
            ctx.arc(x, y, 8, 0, 2 * Math.PI);
            ctx.fillStyle = value === 1 ? '#ef4444' : '#22c55e';
            ctx.fill();
            ctx.strokeStyle = '#1e293b';
            ctx.lineWidth = 2;
            ctx.stroke();
            // 标签
            ctx.fillStyle = '#1e293b';
            ctx.font = 'bold 16px "Segoe UI", sans-serif';
            ctx.textAlign = 'right';
            ctx.textBaseline = 'middle';
            ctx.fillText(label, x - 18, y);
        }

        // 主绘制函数
        function drawScene() {
            ctx.clearRect(0, 0, 800, 500);

            // ---- 绘制两个与非门 ----
            // 门1 (左边) 输出连接到门2的一个输入; 门2输出连接到门1的一个输入
            // 布局: 左上门 (G1) 朝右? 我们让门1朝向右边 (输出在右, 小圆在右) 吗? 
            // 但是为了交叉连线, 我们让门1输出在左边, 门2输出在右边，这样连线形成交叉。
            // 根据锁存器结构: G1输出 -> G2的一个输入; G2输出 -> G1的一个输入。
            // 所以我们让G1输出端朝左, G2输出端朝右, 这样它们输出相对, 连线直接水平交叉。
            // G1: 输出在左 (x=G1_X), 输入在右 (x=G1_X+GATE_SIZE)
            // G2: 输出在右 (x=G2_X), 输入在左 (x=G2_X-GATE_SIZE)
            const gate1 = drawNAND(G1_X, G1_Y, 'left');   // 输出在左
            const gate2 = drawNAND(G2_X, G2_Y, 'right');  // 输出在右

            // 获取连接点
            // gate1.output 是输出点 (带小圆的中心)
            // gate1.inputs 是两条输入线右端点
            // gate2.output 是输出点
            // gate2.inputs 是两条输入线左端点

            // ---- 绘制交叉连线 ----
            // 连线1: gate1.output (左) -> gate2.inputs[0] (第一个输入)
            // 连线2: gate2.output (右) -> gate1.inputs[1] (第二个输入)
            // 连线需要拐弯，避免重叠: 先垂直再水平再垂直
            // 拐点坐标
            const midY1 = (gate1.output.y + gate2.inputs[0].y) / 2;
            const midY2 = (gate2.output.y + gate1.inputs[1].y) / 2;

            // 连线1: gate1输出 -> gate2输入0
            drawLine([
                gate1.output,
                { x: gate1.output.x, y: midY1 },
                { x: gate2.inputs[0].x, y: midY1 },
                gate2.inputs[0]
            ], '#334155', 2);

            // 连线2: gate2输出 -> gate1输入1
            drawLine([
                gate2.output,
                { x: gate2.output.x, y: midY2 },
                { x: gate1.inputs[1].x, y: midY2 },
                gate1.inputs[1]
            ], '#334155', 2);

            // ---- 绘制输入 S 和 R 的连接 ----
            // S 输入连接到 gate1 的 input[0] (上面那个输入)
            // R 输入连接到 gate2 的 input[1] (下面那个输入)  ?? 
            // 标准 SR: S -> G1输入, R -> G2输入. G1输出->G2输入, G2输出->G1输入.
            // 我们给门标号: 门1 (左) 输出 Qbar, 门2 (右) 输出 Q? 
            // 通常 Q = G2输出, Qbar = G1输出. 那么 S 进入 G1 的输入, R 进入 G2 的输入.
            // 所以 S 连接到 gate1.inputs[0], R 连接到 gate2.inputs[1].
            // 但也要考虑交叉连线已经用了 gate1.inputs[1] 和 gate2.inputs[0] 作为反馈.
            // 所以 S 接 gate1.inputs[0], R 接 gate2.inputs[1].
            const S_pin = gate1.inputs[0];   // 上面输入
            const R_pin = gate2.inputs[1];   // 下面输入

            // 从左侧引入 S 信号
            const S_origin = { x: 50, y: S_pin.y };
            drawLine([S_origin, { x: S_origin.x, y: S_pin.y }, S_pin], '#1e293b', 2);
            drawInputPin(S_origin.x, S_origin.y, S, 'S');

            // 从右侧引入 R 信号
            const R_origin = { x: 750, y: R_pin.y };
            drawLine([R_origin, { x: R_origin.x, y: R_pin.y }, R_pin], '#1e293b', 2);
            drawInputPin(R_origin.x, R_origin.y, R, 'R');

            // ---- 绘制输出灯泡 ----
            // Q 来自 gate2 输出 (右边门输出)
            const Q_pos = { x: gate2.output.x + 40, y: gate2.output.y };
            drawLine([gate2.output, Q_pos], '#1e293b', 2);
            drawBulb(Q_pos.x + 30, Q_pos.y, 18, Q, 'Q');

            // Qbar 来自 gate1 输出 (左边门输出)
            const Qbar_pos = { x: gate1.output.x - 40, y: gate1.output.y };
            drawLine([gate1.output, Qbar_pos], '#1e293b', 2);
            drawBulb(Qbar_pos.x - 30, Qbar_pos.y, 18, Qbar, 'Q̅');

            // 额外标注门
            ctx.fillStyle = '#1e293b';
            ctx.font = 'italic 14px "Segoe UI", sans-serif';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'bottom';
            ctx.fillText('G1', G1_X, G1_Y - GATE_HEIGHT/2 - 8);
            ctx.fillText('G2', G2_X, G2_Y - GATE_HEIGHT/2 - 8);

            // ---- 更新文字显示 ----
            qDisplay.textContent = Q;
            qbarDisplay.textContent = Qbar;
            btnS.textContent = S;
            btnR.textContent = R;

            // 按钮样式
            btnS.classList.toggle('active', S === 0);
            btnR.classList.toggle('active', R === 0);

            // 状态徽章
            if (S === 0 && R === 0) {
                stateBadge.textContent = '⚠️ 非法状态 (S=0, R=0)';
                stateBadge.className = 'badge illegal';
            } else {
                stateBadge.textContent = '正常';
                stateBadge.className = 'badge normal';
            }
        }

        // 更新锁存器状态 (根据真值表)
        function updateLatch() {
            // SR 锁存器 (与非门) 真值表：
            // S=1, R=1 -> 保持 (Q不变)
            // S=0, R=1 -> 置位 (Q=1)
            // S=1, R=0 -> 复位 (Q=0)
            // S=0, R=0 -> 非法 (Q=1, Qbar=1)
            if (S === 0 && R === 0) {
                // 非法状态
                Q = 1;
                Qbar = 1;
            } else if (S === 0 && R === 1) {
                Q = 1;
                Qbar = 0;
            } else if (S === 1 && R === 0) {
                Q = 0;
                Qbar = 1;
            } else {
                // S=1, R=1: 保持 (不变)
                // 不需要操作，变量保持
            }
        }

        // 切换输入
        function toggleInput(inputName) {
            if (inputName === 'S') {
                S = S === 1 ? 0 : 1;
            } else if (inputName === 'R') {
                R = R === 1 ? 0 : 1;
            }
            updateLatch();
            drawScene();
        }

        // 按钮事件绑定
        btnS.addEventListener('click', function() {
            toggleInput('S');
        });
        btnR.addEventListener('click', function() {
            toggleInput('R');
        });

        // 初始化绘制
        updateLatch();  // 根据初始S=1,R=1计算Q和Qbar (保持上一次, 但第一次我们设默认Q=1,Qbar=0)
        // 强制初始状态 (S=1,R=1 -> 保持, 我们预设Q=1,Qbar=0)
        Q = 1;
        Qbar = 0;
        drawScene();
    })();
</script>
</body>
</html>
