            for (let i = 0; i < MAX_PARTICLES; i++) {
                if (lifetimes[i] <= 0 && sizes[i] === 0) {
                    // Check if already in pool? avoid duplicates.
                    // We'll just ensure it's not already in pool by checking a flag? simpler: 
