                    // Let's use a simpler approach: after a particle dies, we set lifetimes[i] = -1 to mark as fully dead.
                    // Then in the main loop we don't process it.
                    // Actually better: keep deadIndices as a set of indices that are available.
                    // But we don't want to push the same index multiple times.
                    // So we'll only push when a particle transitions from alive to dead.
                }
            }

            // Actually manage dead pool properly: 
            // We'll track which particles died this frame and recycle them.
            // But for simplicity, we can just push any particle that is dead and not already in pool? 
            // That's messy. Let's do it cleanly: each frame, we reset deadIndices and rebuild from particles that are dead.
            // But that's O(n) each frame. For 8000 particles it's fine.
            // We'll rebuild deadIndices every frame (or every few frames). Let's do it every frame to be clean.
            deadIndices.length = 0;
            for (let i = 0; i < MAX_PARTICLES; i++) {
                if (lifetimes[i] <= 0) {
                    deadIndices.push(i);
                }
            }

            // --- Spawn new explosions periodically ---
            timeSinceLastSpawn += delta;
            if (timeSinceLastSpawn > spawnInterval) {
                timeSinceLastSpawn = 0;
                // Spawn 1-3 explosions
                const count = 1 + Math.floor(Math.random() * 3);
                for (let i = 0; i < count; i++) {
                    if (deadIndices.length > 20) { // ensure we have enough particles
                        spawnExplosion();
                    }
                }
            }

            // Update controls
            controls.update();

            // Render
            renderer.render(scene, camera);
            requestAnimationFrame(animate);
        }

        animate();

        // --- Window Resize ---
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        // --- Restart Button ---
        document.getElementById('restartBtn').addEventListener('click', () => {
            restartExplosions();
            // Also reset time to avoid immediate burst
            timeSinceLastSpawn = 0;
        });

        // --- Help text fade ---
        setTimeout(() => {
            const info = document.getElementById('info');
            if (info) info.style.opacity = '0.6';
        }, 3000);

        console.log('Firecracker animation running. Max particles:', MAX_PARTICLES);
    </script>
