    size: 0.4,
    blending: THREE.AdditiveBlending,
    depthWrite: false,
    transparent: true,
    vertexColors: true,
    opacity: 1,
    sizeAttenuation: true,
});
const sparkPoints = new THREE.Points(sparkGeometry, sparkMaterial);
scene.add(sparkPoints);

// Smoke geometry and material
const smokeGeometry = new THREE.BufferGeometry();
smokeGeometry.setAttribute('position', new THREE.BufferAttribute(smokePos, 3));
smokeGeometry.setAttribute('color', new THREE.BufferAttribute(smokeColor, 3));
smokeGeometry.setAttribute('size', new THREE.BufferAttribute(smokeSize, 1));

const smokeMaterial = new THREE.PointsMaterial({
    map: spriteMap,
    size: 1.2,
    blending: THREE.NormalBlending,
    depthWrite: false,
    transparent: true,
    vertexColors: true,
    opacity: 0.4,
    sizeAttenuation: true,
});
const smokePoints = new THREE.Points(smokeGeometry, smokeMaterial);
scene.add(smokePoints);

// --- Spawning logic ---
let timeToNextExplosion = 1.0;

function spawnExplosion() {
    // Random position inside container, not too close to walls
    const angle = Math.random() * Math.PI * 2;
    const r = (containerRadius - 1.0) * Math.random();
    const x = r * Math.cos(angle);
    const z = r * Math.sin(angle);
    const y = (containerHeight - 1.5) * (Math.random() - 0.5);

    const origin = new THREE.Vector3(x, y, z);

    // Spawn sparks (40-80)
    const sparkCount = 40 + Math.floor(Math.random() * 40);
    for (let i = 0; i < sparkCount; i++) {
        const idx = getNextInactive(sparkActive, MAX_SPARKS);
        if (idx === -1) break;
        sparkActive[idx] = 1;
        // position at origin
        sparkPos[idx*3] = origin.x;
        sparkPos[idx*3+1] = origin.y;
        sparkPos[idx*3+2] = origin.z;
        // random velocity, biased upward slightly
        const theta = Math.random() * Math.PI * 2;
        const phi = Math.random() * Math.PI;
        const speed = 2 + Math.random() * 5;
        const vx = speed * Math.sin(phi) * Math.cos(theta);
        const vy = speed * Math.cos(phi) + 1.0; // upward bias
        const vz = speed * Math.sin(phi) * Math.sin(theta);
        sparkVel[idx].set(vx, vy, vz);
        // color: bright yellow to red
        const t = Math.random();
        sparkColor[idx*3] = 1.0;
        sparkColor[idx*3+1] = 0.3 + t * 0.7;
        sparkColor[idx*3+2] = 0.0 + t * 0.3;
        // size
        sparkSize[idx] = 0.2 + Math.random() * 0.3;
        // lifetime
        sparkAge[idx] = 0;
        sparkMaxAge[idx] = 0.8 + Math.random() * 1.2;
    }

    // Spawn smoke (15-30)
    const smokeCount = 15 + Math.floor(Math.random() * 15);
    for (let i = 0; i < smokeCount; i++) {
        const idx = getNextInactive(smokeActive, MAX_SMOKE);
        if (idx === -1) break;
        smokeActive[idx] = 1;
        smokePos[idx*3] = origin.x + (Math.random()-0.5)*0.5;
        smokePos[idx*3+1] = origin.y + (Math.random()-0.5)*0.5;
        smokePos[idx*3+2] = origin.z + (Math.random()-0.5)*0.5;
        const theta = Math.random() * Math.PI * 2;
        const phi = Math.random() * Math.PI * 0.5; // upward
        const speed = 0.5 + Math.random() * 1.5;
        const vx = speed * Math.sin(phi) * Math.cos(theta);
        const vy = speed * Math.cos(phi) + 0.5;
        const vz = speed * Math.sin(phi) * Math.sin(theta);
        smokeVel[idx].set(vx, vy, vz);
        const gray = 0.3 + Math.random() * 0.3;
        smokeColor[idx*3] = gray;
        smokeColor[idx*3+1] = gray;
        smokeColor[idx*3+2] = gray;
        smokeSize[idx] = 0.8 + Math.random() * 1.0;
        smokeAge[idx] = 0;
        smokeMaxAge[idx] = 2.5 + Math.random() * 2.5;
    }
}

// --- Physics update ---
const clock = new THREE.Clock();
const bounceDamping = 0.6;
const drag = 0.98; // per frame velocity multiplier

function updateParticles(delta) {
    const halfHeight = containerHeight / 2;
    const radiusSq = containerRadius * containerRadius;

    // Update sparks
    let sparkPosAttr = sparkGeometry.attributes.position;
    let sparkColorAttr = sparkGeometry.attributes.color;
    let sparkSizeAttr = sparkGeometry.attributes.size;
    for (let i = 0; i < MAX_SPARKS; i++) {
        if (!sparkActive[i]) {
            // hide particle
            sparkPos[i*3] = 0;
            sparkPos[i*3+1] = 0;
            sparkPos[i*3+2] = 0;
            continue;
        }
        sparkAge[i] += delta;
        if (sparkAge[i] >= sparkMaxAge[i]) {
            sparkActive[i] = 0;
            sparkPos[i*3] = 0;
            sparkPos[i*3+1] = 0;
            sparkPos[i*3+2] = 0;
            continue;
        }

        // Apply velocity
        const v = sparkVel[i];
        v.multiplyScalar(drag); // drag
        // gravity (slight)
        v.y -= delta * 1.5;
        // update position
        const px = sparkPos[i*3] + v.x * delta;
        const py = sparkPos[i*3+1] + v.y * delta;
        const pz = sparkPos[i*3+2] + v.z * delta;

        // Collision with cylinder walls
        // Check if inside cylinder: x^2+z^2 < radius^2 and |y| < halfHeight
        let inside = true;
        // Radial bounce
        const rad2 = px*px + pz*pz;
        if (rad2 > radiusSq) {
            const rad = Math.sqrt(rad2);
            const nx = px / rad;
            const nz = pz / rad;
            const dot = v.x * nx + v.z * nz;
            if (dot > 0) { // moving outward
                v.x -= 2 * dot * nx;
                v.z -= 2 * dot * nz;
                v.multiplyScalar(bounceDamping);
                // reposition just inside
                const newRad = containerRadius - 0.01;
                sparkPos[i*3] = nx * newRad;
                sparkPos[i*3+2] = nz * newRad;
                sparkPos[i*3+1] = py; // keep y
            } else {
                sparkPos[i*3] = px;
                sparkPos[i*3+1] = py;
                sparkPos[i*3+2] = pz;
            }
            inside = false;
        } else {
            sparkPos[i*3] = px;
            sparkPos[i*3+1] = py;
            sparkPos[i*3+2] = pz;
        }
        // Vertical bounce
        if (py > halfHeight || py < -halfHeight) {
            if (py > halfHeight) {
                sparkPos[i*3+1] = halfHeight - 0.01;
                if (v.y > 0) v.y = -v.y * bounceDamping;
            } else {
                sparkPos[i*3+1] = -halfHeight + 0.01;
                if (v.y < 0) v.y = -v.y * bounceDamping;
            }
        }

        // Fade alpha based on remaining life
        const life = 1 - sparkAge[i] / sparkMaxAge[i];
        // We can't easily change opacity per particle with PointsMaterial, but we can scale size to give fading illusion
        // Actually, with vertex colors we can modulate alpha if material has vertexColors and we set color alpha, but PointsMaterial ignores vertex color alpha.
        // So we'll scale size.
        sparkSize[i] = (0.2 + Math.random() * 0.3) * life;
        // Also brighten color slightly at peak?
        // Keep color constant, but we could adjust but fine.
    }
    sparkPosAttr.needsUpdate = true;
    sparkColorAttr.needsUpdate = true;
    sparkSizeAttr.needsUpdate = true;

    // Update smoke
    for (let i = 0; i < MAX_SMOKE; i++) {
        if (!smokeActive[i]) {
            smokePos[i*3] = 0;
            smokePos[i*3+1] = 0;
            smokePos[i*3+2] = 0;
            continue;
        }
        smokeAge[i] += delta;
        if (smokeAge[i] >= smokeMaxAge[i]) {
            smokeActive[i] = 0;
            smokePos[i*3] = 0;
            smokePos[i*3+1] = 0;
            smokePos[i*3+2] = 0;
            continue;
        }

        const v = smokeVel[i];
        v.multiplyScalar(0.98);
        v.y += delta * 0.3; // slow rise
        const px = smokePos[i*3] + v.x * delta;
        const py = smokePos[i*3+1] + v.y * delta;
        const pz = smokePos[i*3+2] + v.z * delta;

        // Collision (smoke just fades, but keep inside roughly)
        const rad2 = px*px + pz*pz;
        if (rad2 > radiusSq) {
            const rad = Math.sqrt(rad2);
            const nx = px / rad;
            const nz = pz / rad;
            const newRad = containerRadius - 0.1;
            smokePos[i*3] = nx * newRad;
            smokePos[i*3+2] = nz * newRad;
            smokePos[i*3+1] = Math.max(-halfHeight, Math.min(halfHeight, py));
            continue;
        }
        if (py > halfHeight) {
            smokePos[i*3+1] = halfHeight - 0.1;
        } else if (py < -halfHeight) {
            smokePos[i*3+1] = -halfHeight + 0.1;
        } else {
            smokePos[i*3] = px;
            smokePos[i*3+1] = py;
            smokePos[i*3+2] = pz;
        }

        // Increase size and fade opacity via size and material opacity (but we can't set per-particle opacity, so we'll rely on global material opacity change)
        const life = 1 - smokeAge[i] / smokeMaxAge[i];
        smokeSize[i] = (0.8 + Math.random()) * (1 + (1 - life) * 2);
        // Use size to emulate fading; also we'll set material opacity based on overall life? We'll just let it work.
    }
    let smokePosAttr = smokeGeometry.attributes.position;
    let smokeSizeAttr = smokeGeometry.attributes.size;
    smokePosAttr.needsUpdate = true;
    smokeSizeAttr.needsUpdate = true;
}

// --- Animation loop ---
function animate() {
    const delta = clock.getDelta();
    // Clamp delta to avoid huge jumps
    const dt = Math.min(delta, 0.05);

    // Spawn explosions periodically
    timeToNextExplosion -= dt;
    if (timeToNextExplosion <= 0) {
        spawnExplosion();
        timeToNextExplosion = 0.8 + Math.random() * 1.5;
    }

    updateParticles(dt);

    controls.update();
    renderer.render(scene, camera);
    requestAnimationFrame(animate);
}

animate();

// --- Window resize ---
window.addEventListener('resize', () => {
    camera.aspect = window.innerWidth / window.innerHeight;
    camera.updateProjectionMatrix();
    renderer.setSize(window.innerWidth, window.innerHeight);
});

console.log('Firecracker simulation started.');
</script>
